  R("instruments", {"policy_rate":{"name":"Merkez Bankası Politika Faizi","desc":"Para politikasının ana aracı. Artış enflasyonu ve kuru baskılar; büyümeyi yavaşlatır. Ucuz başlar; her onaylanan kullanımda siyasi sermaye maliyeti +1 artar."},"tax_rate":{"name":"Vergi Oranı","desc":"Genel vergi yükü. Borcu rahatlatır ama büyümeyi ve onayı sıkar. Düşük taban maliyet; her onayda +1 siyasi sermaye."},"public_spending":{"name":"Kamu Harcaması / Borçlanma","desc":"Kamu yatırımı ve harcama. Büyümeyi canlandırır; borç ve enflasyon üretir. Düşük taban maliyet; her onayda +1 siyasi sermaye."},"fx_intervention":{"name":"Döviz Müdahalesi","desc":"Rezerv satarak kuru savunmak (maliyet 3). Sık kullanım siyasi sermaye yenilenmesini aşındırır (her 4 kullanımda −1 regen); enflasyon ~4 çeyrek gecikmeyle hafif yükselir. Açık kaldıkça rezerv hızla erir."},"qe":{"name":"Miktarsal Gevşeme (QE / Bilanço)","desc":"Merkez bankası varlık alımıyla likidite basmak. Büyüme ve varlık fiyatlarını destekler; enflasyon ve kur riski yaratır."},"reserve_currency":{"name":"Rezerv Para Birimi Statüsü İnşası","desc":"Kendi para biriminle enerji ve emtia ticaretini zorlamak. 8 yıllık dev proje."},"alt_finance":{"name":"Alternatif Finansal Altyapı (SWIFT Rakibi)","desc":"Yaptırımlara dirençli alternatif ödeme sistemi kurmak ve yaygınlaştırmak."},"capital_markets":{"name":"Derin Sermaye Piyasaları Oluşturmak","desc":"Tahvil ve hisse piyasalarını küresel yatırımcılar için güvenli liman yapmak."},"cbdc":{"name":"CBDC ile Dolarsızlaşma","desc":"Sınır ötesi ödemelerde programlanabilir dijital merkez bankası parası."},"infra_corridor":{"name":"Altyapı Kuşağı ve Ulaştırma Koridorları","desc":"Büyük altyapı projeleriyle küresel tedarik zincirlerini kendine bağlamak."},"brain_gain":{"name":"Beyin Göçü Programı","desc":"Seçici vize ve vatandaşlıkla nitelikli insan çekmek. Ar-Ge kapasitesini büyütür; bütçe ve toplumsal gerilim maliyeti vardır."},"migration_weapon":{"name":"Göç Silahı","desc":"Sınırları kontrollü açarak hedef ülkenin sosyal ve bütçe yükünü artırmak."},"eez_expansion":{"name":"Stratejik Deniz Yetki Alanı Genişletme","desc":"MEB ilanları ve kıta sahanlığı başvurularıyla kaynak haklarını büyütmek."},"space_deepsea":{"name":"Uzay ve Derin Deniz Kaynakları","desc":"Uzay madenciliği ve okyanus tabanına yatırım. Geleceğin kaynaklarında avantaj."},"tech_standards":{"name":"Teknoloji Standartlarını Dikte Etmek","desc":"5G/6G ve yapay zeka standartlarını küresel norm haline getirmek."},"ip_regime":{"name":"Kapsamlı Fikri Mülkiyet Rejimi","desc":"Patent ve tasarımları uluslararası anlaşmalarla korumak; değer zincirinden pay almak."},"edu_export":{"name":"Eğitim ve Dil İhracatı","desc":"Burs programları, kampüsler ve dil kurslarıyla yumuşak güç inşası."},"brussels_effect":{"name":"Hukuki Empoze (Brüksel Etkisi)","desc":"Kendi regülasyonlarını küresel şirketlere dayatmak."},"rd_policy":{"name":"Stratejik Ar-Ge ve Sanayi Politikası","desc":"Devlet destekli Ar-Ge, teknoloji parkları ve ileri sanayi yatırımı. Uzun vadeli verimlilik artışı."},"chokepoint":{"name":"Tedarik Zinciri Silahlaştırması","desc":"Kritik hammadde ihracatına kota/lisans getirmek. Küresel üretimi sarsar; kendi ihracatın da daralır."},"subsidy":{"name":"Sübvansiyon Savaşları","desc":"Stratejik sektörlere devlet teşviki. Yerli üretici güçlenir, bütçe zorlanır; aşırı kullanım enflasyon üretir."},"anti_dumping":{"name":"Anti-Damping ve Telafi Edici Vergi","desc":"\"Haksız rekabet\" gerekçesiyle korunma önlemleri. İthalatı kısar, iç fiyatları yükseltir."},"strategic_stock":{"name":"Stratejik Stok Yönetimi","desc":"Petrol, gıda, tahıl stok seviyesi. Yüksek stok iç fiyatları korur; alım döneminde küresel fiyatı iter."},"capital_controls":{"name":"Makro-İhtiyati Tedbirler (Sermaye Kontrolü)","desc":"Sıcak para giriş/çıkışını zorlaştırmak. Kur şoklarını azaltır, yatırımcıyı ürkütür, büyüme yavaşlar."},"shadow_fx":{"name":"Gölge Döviz Piyasası Müdahalesi","desc":"Kamu bankalarıyla gizli kur müdahalesi. Görünmez ama rezervi eritir; enflasyon yüksekse etkinliği düşer."},"debt_trap":{"name":"Borç Tuzağı Diplomasisi","desc":"Hedefe ödeyemeyeceği stratejik kredi açmak. Kısa vadede hedef büyür; orta vadede borç bağımlılığı ve nüfuz."},"secondary_sanctions":{"name":"İkincil Yaptırımlar","desc":"Hedefle ticaret yapan üçüncü tarafları da cezalandırmak. Etki alanı geniş, küresel ticaret ve kendi ihracatın da zarar görür."},"asset_freeze":{"name":"Varlık Dondurma ve El Koyma","desc":"Hedefin merkez bankası rezervlerine ve elit varlıklarına el koymak. Etki hedefin rezerv büyüklüğüne ve senin finansal gücüne bağlıdır."},"service_ban":{"name":"Teknik Servis Yasağı","desc":"Uçak motoru, yazılım, bakım hizmetlerini kesmek. Hedefin altyapısı yavaşça çöker; senin firmaların da ciro kaybeder."},"food_weapon":{"name":"Gıda ve Tohum Silahı","desc":"Gıda ihracatını yasaklamak veya tohum bağımlılığı yaratmak. Gıda ihracatçılarında tam etki; ithalatçılarda zayıf."},"energy_weapon":{"name":"Enerji İhracat Kısıtı / Enerji Silahı","desc":"Petrol/gaz ihracatını kısıtlayarak hedefi ve küresel enerji fiyatlarını vurmak. Enerji ihracatçılarında güçlü; aksi halde zayıf."},"tariff":{"name":"Genel Gümrük Tarifesi","desc":"Hedef ülkeye karşı genel gümrük duvarı. Yerli sanayiyi korur, enflasyon ve misilleme riski yaratır."},"export_credit":{"name":"İhracat Kredisi ve Exim Desteği","desc":"İhracatçılara ucuz kredi ve garanti. Ticaret dengesini ve büyümeyi destekler; bütçe ve risk maliyeti vardır."},"currency_swap":{"name":"İkili Döviz Swap Hattı","desc":"Hedefle karşılıklı döviz swap anlaşması. Her iki tarafta da likidite ve güven artar; ilişki güçlenir."},"price_controls":{"name":"Fiyat Kontrolleri","desc":"Temel mallarda tavan fiyat. Kısa vadede enflasyonu ve öfkeyi bastırır; orta vadede kıtlık, kara borsa ve yatırım cayması."},"aid_diplomacy":{"name":"Kalkınma Yardımı Diplomasisi","desc":"Hedefe ekonomik yardım ve yumuşak kredi. İlişki ve nüfuz kazanırsın; bütçe ve rezerv maliyeti vardır."},"espionage":{"name":"Ekonomik Casusluk ve Rekabet İstihbaratı","desc":"Devlet destekli siber operasyonlarla Ar-Ge sırlarını almak."},"insider_trading":{"name":"İçeriden Öğrenenlerin Ticareti (Devlet Bağlantılı)","desc":"Jeopolitik bilgiyle borsada pozisyon almak. Rezervi büyütür, skandalı büyük olur."},"rating_pressure":{"name":"Derecelendirme ve Endeks Baskısı","desc":"Hedefin kredi notunu siyasi baskıyla düşürtmek, endekslerden çıkartmak. Finans merkezleri daha etkili."},"national_champion":{"name":"Kartel ve Tekel Teşvikleri (Ulusal Şampiyon)","desc":"Yerli devlerin birleşmesine izin vererek küresel rekabet gücü yaratmak. Verimlilik artar, rekabet ve fiyat disiplini bozulur."},"patent_revoke":{"name":"Lisans ve Patent İptalleri","desc":"Zorunlu lisanslama veya yabancı patentleri geçersiz kılmak. Kısa vadeli üretim kazancı, uzun vadeli itibar kaybı."},"cert_weapon":{"name":"Sertifikasyon Silahlaştırma","desc":"Helal/organik/etik standartları ticaret engeline dönüştürmek."},"jawboning":{"name":"Piyasa Duyarlılığı Yönetimi (Jawboning)","desc":"Üst düzey açıklamalarla piyasa algısını yönlendirmek. Ucuz ama kısa ömürlü; aşırı kullanım güveni aşındırır."},"disinfo":{"name":"Dezenformasyon ve Kara Propaganda","desc":"Hedefin bankacılık sistemi hakkında panik söylentileri yaymak."},"ngo_use":{"name":"Devlet Dışı Aktörlerin Kullanımı (NGO)","desc":"Fonlanan STK'larla hedef ülkede protesto ve siyasi baskı üretmek."},"corruption_net":{"name":"Yolsuzluk ve Nüfuz Ticareti","desc":"Gri ödemelerle yabancı yetkililer üzerinde nüfuz kurmak."},"insurgency_finance":{"name":"İsyanın Ekonomik Finansmanı","desc":"Hedef ülkedeki ayrılıkçı grupları ekonomik olarak desteklemek. En tehlikeli araç."},"lawfare":{"name":"Uluslararası Hukuk İstismarı (Lawfare)","desc":"Yatırım anlaşmaları ve mahkemeler üzerinden sürekli dava baskısı."}});
  R("countries", {"USA":{"name":"ABD","desc":"Hegemonya ve rezerv para avantajı. Küresel etki yaratan müdahaleler için ideal; beklenti ve sorumluluk çok yüksek.","style":"Küresel etki yaratan müdahaleler","difficulty":"Zor","gov":"demokratik"},"CHN":{"name":"Çin","desc":"Devlet kontrolü yüksek, uzun vadeli planlama. Yapısal projeler ve tedarik zinciri silahlaştırması için güçlü.","style":"Yapısal projeler + tedarik zinciri","difficulty":"Orta-Zor","gov":"otoriter"},"EU":{"name":"Avrupa Birliği","desc":"27 üyeli ekonomik dev. Brüksel etkisi, regülasyon ve ihracat gücü yüksek; enerji ve jeopolitik koordine karar yavaş.","style":"Regülasyon + ihracat + diplomasi","difficulty":"Orta","gov":"birlik"},"JPN":{"name":"Japonya","desc":"Teknoloji ve finans gücü; yaşlanan nüfus ve dev kamu borcu. Standart dikte ve sermaye piyasaları ana silah.","style":"Teknoloji standartları + finans","difficulty":"Orta","gov":"demokratik"},"IND":{"name":"Hindistan","desc":"Hızla yükselen dev iç pazar. Altyapı ve enerji açığı zayıf nokta; uzun vadeli reform ve demografi avantajı.","style":"Uzun vadeli yapısal reformlar","difficulty":"Orta","gov":"demokratik"},"GBR":{"name":"Birleşik Krallık","desc":"Finans merkezi ve soft power. Brexit sonrası AB ile rekabet; City of London ve Anglo-sakson ittifakı güçlü.","style":"Finans + diplomasi + soft power","difficulty":"Orta","gov":"demokratik"},"RUS":{"name":"Rusya","desc":"Enerji kartı güçlü ama yaptırımlara açık. Enerji silahı ve gri alan taktikleri; izolasyon riski yüksek.","style":"Enerji silahı + gri alan","difficulty":"Zor","gov":"otoriter"},"CAN":{"name":"Kanada","desc":"Kaynak zengini, ABD'ye sıkı bağlı. Emtia, enerji ve istikrarlı kurumlar; bağımsız jeopolitik manevra alanı dar.","style":"Emtia + istikrar + ABD ekseni","difficulty":"Kolay-Orta","gov":"demokratik"},"BRA":{"name":"Brezilya","desc":"Gıda ve maden devi. Emtia fiyatı ve stok yönetimiyle oynanır; siyasi dalgalanma riski.","style":"Emtia fiyatı manipülasyonu","difficulty":"Kolay-Orta","gov":"demokratik"},"KOR":{"name":"Güney Kore","desc":"Çip ve sanayi devi; jeopolitik sıkışma (ABD-Çin-Kuzey). Teknoloji standartları ve ihracat odaklı.","style":"Yarı iletken + ihracat","difficulty":"Orta","gov":"demokratik"},"AUS":{"name":"Avustralya","desc":"Maden ve LNG ihracatçısı; Çin talebine bağımlı. AUKUS ve Anglo-sakson ittifakı jeopolitik omurga.","style":"Maden/LNG + müttefik ağı","difficulty":"Kolay-Orta","gov":"demokratik"},"MEX":{"name":"Meksika","desc":"ABD üretim hattı ve nearshoring kazananı. Enerji reformu ve iç güvenlik istikrarı kritik.","style":"Nearshoring + ABD ticareti","difficulty":"Orta","gov":"demokratik"},"IDN":{"name":"Endonezya","desc":"Güneydoğu Asya'nın devi; nikel ve kritik mineraller. Genç nüfus, altyapı açığı ve emtia döngüsü.","style":"Kritik mineraller + demografik güç","difficulty":"Orta","gov":"demokratik"},"SAU":{"name":"Suudi Arabistan","desc":"Petrol süper gücü ve OPEC+ ağırlığı. Vizyon 2030 ile diversifikasyon; enerji silahı ve sermaye ihracı.","style":"Petrol kartı + egemen servet","difficulty":"Orta","gov":"otoriter"},"TUR":{"name":"Türkiye","desc":"Bölgesel güç ve lojistik köprü; kronik enflasyon hassasiyeti. Dengeli diplomasi ve fırsatçı müdahaleler.","style":"Dengeli diplomasi + fırsatçılık","difficulty":"Orta","gov":"hibrit"},"CHE":{"name":"İsviçre","desc":"Küresel finans ve pharma sığınağı. Tarafsızlık + bankacılık gücü; yaptırım ve gri finans baskısına açık.","style":"Finans sığınağı + yüksek katma değer","difficulty":"Orta","gov":"demokratik"},"ZAF":{"name":"Güney Afrika","desc":"Afrika'nın en büyük sanayi ekonomisi ve BRICS üyesi. Maden ihracatı güçlü; enerji ve istikrar zayıf nokta.","style":"Maden + BRICS diplomasisi","difficulty":"Orta","gov":"demokratik"}});
  R("disasters", {"volcano":{"name":"Süper Volkan Patlaması","desc":"Devasa bir volkanik patlama atmosferi külle kapladı. Küresel hava trafiğinin %60-70'i durdu, tarım ürünleri fiyatları fırlıyor.","impacts":["<b>Kısa vade:</b> Hava trafiği durdu, tarım fiyatları sert yükseliyor.","<b>Orta vade:</b> Tedarik zincirleri bölgeselleşiyor, turizm çöküyor.","<b>Uzun vade:</b> Küresel lojistik mimarisi kalıcı olarak değişecek."]},"suez":{"name":"Süveyş Kanalı Uzun Süreli Tıkanması","desc":"Zincirleme kazalar ve çökme sonucu Süveyş Kanalı yıllarca kapanacak şekilde tıkandı. Avrupa-Asya ticareti %40 sekteye uğradı, navlun 3-4 katına çıkıyor.","impacts":["<b>Kısa vade:</b> Avrupa-Asya ticareti %35-45 düştü, nakliye 3-4 kat pahalandı.","<b>Orta vade:</b> Alternatif rotalar (Orta Koridor, Kuzey Yolu) hızlanıyor.","<b>Uzun vade:</b> Ticaret rotaları kalıcı olarak çeşitlenecek."]},"megahurricane":{"name":"ABD'yi Vuran Mega Kasırga Serisi","desc":"Art arda gelen 5. kategori kasırgalar ABD'nin doğu kıyısını ve körfezi yıktı. ABD ekonomisi serbest düşüşte, sigorta sektörü çöküyor.","impacts":["<b>Kısa vade:</b> ABD GDP'si 2 yılda %8-12 düşüyor, sigorta sektörü ağır yaralı.","<b>Orta vade:</b> Dolar hegemonyası zayıflıyor, ABD iç siyaseti kutuplaşıyor.","<b>Uzun vade:</b> ABD liderliği sorgulanacak, yeni güç odakları doğacak."]},"china_quake":{"name":"Çin Teknoloji Merkezinde Büyük Deprem","desc":"Shenzhen-Guangdong hattını vuran 8.4'lük deprem, dünya yarı iletken ve batarya üretiminin %35-40'ını durdurdu.","impacts":["<b>Kısa vade:</b> Küresel çip ve batarya üretiminin %35-40'ı durdu.","<b>Orta vade:</b> Şirketler üretimi çeşitlendirmeye zorlanıyor (\"Çin+1\").","<b>Uzun vade:</b> Teknoloji tedarik zinciri kalıcı olarak yeniden kurulacak."]},"tsunami":{"name":"Giga Tsunami (Tayvan + Doğu Asya)","desc":"Pasifik'te dev bir deniz altı çöküşü Tayvan, Güney Japonya ve Çin kıyılarını vurdu. Küresel çip krizi patladı.","impacts":["<b>Kısa vade:</b> Tayvan ve Doğu Asya kıyıları ağır hasarlı; çip krizi patladı.","<b>Orta vade:</b> Enerji ve teknoloji altyapısı yeniden yapılanıyor.","<b>Uzun vade:</b> Yeni üretim merkezleri (Vietnam, Hindistan, Meksika) yükselecek."]},"summit_attack":{"name":"Büyük Liderler Zirvesinde Terör Saldırısı","desc":"G20 zirvesine yapılan saldırıda büyük güçlerin liderleri hayatını kaybetti. Küresel liderlik boşluğu ve panik dalgası.","impacts":["<b>Kısa vade:</b> Liderlik boşluğu, piyasalarda panik, güvenlik harcamaları fırladı.","<b>Orta vade:</b> İttifaklar yeniden şekilleniyor, belirsizlik sürüyor.","<b>Uzun vade:</b> Çok kutuplu dünya düzeni hızla yerleşecek."]},"oil_depletion":{"name":"Küresel Petrol Yataklarının Ani Tükenişi","desc":"Büyük sahalarda rezervlerin abartıldığı ortaya çıktı; üretim çöktü. Petrol fiyatı aylar içinde 4-5 katına çıkıyor.","impacts":["<b>Kısa vade:</b> Petrol 4-5 katına çıktı; enerji ithalatçıları şokta.","<b>Orta vade:</b> Yeşil enerji ve nükleer yatırımlar tarihi hızda.","<b>Uzun vade:</b> Petrodolar sistemi kalıcı zayıflayacak, yeni enerji düzeni doğacak.","<i>Not: Enerji ihracatçıları (Rusya, Suudi, Kanada) fiyat artışından kazançlı.</i>"]},"supernova":{"name":"Süpernova Kaynaklı Elektromanyetik Fırtına","desc":"Yakın süpernova + güneş fırtınası kombinasyonu uyduları ve şebekeleri vurdu. Elektrik ve internet altyapısı aylarca kesintili.","impacts":["<b>Kısa vade:</b> 6-12 ay elektrik/internet kesintileri; dijital ekonomi felç.","<b>Orta vade:</b> Analog yedek sistemler ve dirençli altyapı önem kazanıyor.","<b>Uzun vade:</b> Dijital bağımlılık azalacak, altyapı tasarımı değişecek."]},"food_crisis":{"name":"Küresel Gıda Krizi","desc":"Eşzamanlı kuraklık, tohum hastalıkları ve gübre kıtlığı tahıl üretimini çökertti. Fiyatlar 2-3 katına çıktı, açlık dalgası başlıyor.","impacts":["<b>Kısa vade:</b> Tahıl fiyatları 2-3 katına çıktı; birçok ülkede açlık dalgası.","<b>Orta vade:</b> Tarım millileşiyor; dikey tarım ve sentetik gıda hızlanıyor.","<b>Uzun vade:</b> Tarım sistemi daha dirençli ama daha pahalı olacak.","<i>Not: Gıda/emtia ihracatçıları (Brezilya, Rusya, Kanada, Avustralya) kazançlı.</i>"]},"brics_currency":{"name":"BRICS+ Yeni Rezerv Parası + Koordineli Dolar Satışı","desc":"BRICS+ bloğu ortak rezerv para birimini ilan etti ve merkez bankaları koordineli dolar satışına başladı. Dolar serbest düşüşte.","impacts":["<b>Kısa vade:</b> Dolar ani değer kaybediyor; gelişen ülkelerde borç krizi patlıyor.","<b>Orta vade:</b> Çok kutuplu finansal sistem güçleniyor.","<b>Uzun vade:</b> Doların rezerv statüsü kalıcı olarak zayıflayacak.","<i>Not: BRICS+ (Çin, Rusya, Hindistan, Brezilya, G. Afrika, Suudi) görece korunaklı.</i>"]}});
