  R("newsCats", {"eko":"Ekonomik Haberler","diplo":"Diplomatik Mesajlar","global":"Küresel Etkiler","ic":"İç Olaylar","gri":"Casusluk / Gri Alan","benim":"Beni Etkileyenler"});
  R("diplo", {"1":["\"{actor}'nin bu adımını anlayışla ve memnuniyetle karşılıyoruz. Koordineli hareket etmeye hazırız.\"","\"Bu cesur kararı destekliyoruz. {actor} ile işbirliğimizi derinleştireceğiz.\"","\"{actor}'nin hamlesi ortak çıkarlarımıza hizmet ediyor. Yanındayız.\"","\"Ortak bir geleceğe katkı sağlayan bu politikayı takdir ediyoruz.\"","\"{actor} ile diyalog kanallarımız her zamankinden açık. Bu adım umut verici.\"","\"Bölgesel istikrara hizmet eden bir hamle; el ele ilerleyebiliriz.\"","\"Ticaret ve yatırım ortaklığımız bu kararla güçlenecek.\"","\"Samimi bir jest. Karşılıklı fayda ilkesiyle ilerlemeye hazırız.\""],"2":["\"Bu kararı not ettik. {actor} ile işbirliği fırsatlarına açığız.\"","\"{actor}'nin adımını olumlu değerlendiriyoruz.\"","\"Yapıcı bir adım. Gelişmeleri memnuniyetle izliyoruz.\"","\"İlk izlenimimiz olumlu; detayları birlikte çalışmak isteriz.\"","\"Bu yönelimin sürdürülebilir olmasını umuyoruz.\"","\"Ortak komitelerimiz bu dosyayı önceliklendirebilir.\"","\"Piyasalar da bu sinyali olumlu okuyor; biz de temkinli iyimseriz.\"","\"Teknik düzeyde diyaloga her zaman açığız.\""],"3":["\"Durumu değerlendiriyoruz. {actor}'nin adımlarını yakından izliyoruz.\"","\"{actor}'nin kararının etkilerini analiz ediyoruz.\"","\"Bu aşamada bir yorumumuz yok; gelişmeleri takip ediyoruz.\"","\"Resmi bir tutum için veri ve zaman gerekiyor.\"","\"Ne destek ne karşıtlık: gözlem modundayız.\"","\"Ulusal çıkarlarımız ışığında dosyayı inceliyoruz.\"","\"Bekle-gör yaklaşımını tercih ediyoruz.\"","\"Diplomatik kanallar açıktır; aceleci yorumdan kaçınıyoruz.\""],"4":["\"Bu kararı endişeyle karşılıyoruz. {actor}'yi yeniden düşünmeye davet ediyoruz.\"","\"{actor}'nin bu adımı ikili ilişkilerimizi olumsuz etkileyebilir. Durumu yakından takip edeceğiz.\"","\"Bu politika bölgesel dengeler açısından kaygı vericidir.\"","\"Karşılıklılık ilkesi unutulmamalı; misilleme seçenekleri masadadır.\"","\"Ticaret ortaklarımızın zarar görmesini istemeyiz; geri adım bekliyoruz.\"","\"Uluslararası normlara aykırı yönelimler kabul edilemez.\"","\"Bu adım güven ortamını zedeliyor. Acil istişare talep ediyoruz.\"","\"Piyasalar zaten fiyatlamaya başladı; siyasi maliyet yükselecektir.\""],"5":["\"{actor}'nin bu düşmanca ve tek taraflı adımı kabul edilemez. Gerekli misilleme önlemlerini alacağız.\"","\"Bu açık bir ekonomik saldırıdır. {actor} bunun bedelini ödeyecektir.\"","\"{actor} ateşle oynuyor. Cevabımız sert olacak.\"","\"Tüm ekonomik ve diplomatik araçlarımızı devreye alıyoruz.\"","\"Bu eylemi egemenliğimize yönelik bir saldırı sayıyoruz.\"","\"Uluslararası toplum {actor}'nin sorumsuzluğunu görecektir.\"","\"Kırmızı çizgiler aşıldı. Artık diyalog değil, savunma zamanı.\"","\"Misilleme paketi hazırlanıyor; piyasalara net mesaj gidecektir.\""]});
  R("econTitle", {"up":["{name}: {meta} yükseldi","{name} — {meta} artışı","{name}'de {meta} tırmanışı","Veri: {name} {meta} yukarı","{name} ekonomisinde {meta} baskısı artıyor"],"down":["{name}: {meta} düştü","{name} — {meta} gerilemesi","{name}'de {meta} yumuşadı","Veri: {name} {meta} aşağı","{name} ekonomisinde {meta} gevşemesi"]});
  R("econBody", {"up":["{meta} {prev}{unit} → {cur}{unit}. Analistler kısa vadeli baskının sürebileceğini belirtiyor.","{meta} {prev}{unit} seviyesinden {cur}{unit} seviyesine çıktı. Piyasalar tepki veriyor.","Son çeyrekte {meta} {prev}{unit} iken şimdi {cur}{unit}. Zincirleme etkiler izleniyor.","{meta} artışı ({prev}{unit} → {cur}{unit}) hanehalkı ve firmaları zorluyor.","Resmi veriler {meta} göstergesini {prev}{unit} → {cur}{unit} gösterdi."],"down":["{meta} {prev}{unit} → {cur}{unit}. Gevşeme sinyali mi, yoksa geçici mi tartışılıyor.","{meta} {prev}{unit} seviyesinden {cur}{unit} seviyesine geriledi.","Son çeyrekte {meta} {prev}{unit} iken şimdi {cur}{unit}.","{meta} düşüşü ({prev}{unit} → {cur}{unit}) politika yapıcıları rahatlattı.","Resmi veriler {meta} göstergesini {prev}{unit} → {cur}{unit} gösterdi."]});
  R("globalTitle", {"up":["{name} endeksi yükseliyor","Küresel {name}: sert artış","{name} piyasalarında tansiyon","{name} endeksi rekor bölgede","Dünya {name} fiyatında sıçrama"],"down":["{name} endeksi geriliyor","Küresel {name}: geri çekilme","{name} piyasalarında sakinleşme","{name} endeksi baskı altında","Dünya {name} fiyatında düşüş"]});
  R("globalBody", ["Tedarik zincirleri yeniden fiyatlanıyor.","İthalatçı ve ihracatçı ülkeler asimetrik etkileniyor.","Merkez bankaları ve bakanlıklar brifing üstüne brifing veriyor.","Vadeli piyasalar volatilite primi istiyor.","Jeopolitik risk primi fiyatlara yansıyor."]);
  R("risk", {"reserves":[{"t":"Döviz rezervi kritik seviyede","b":"Rezervler {v} milyar dolara düştü. Kur savunma kapasitemiz tükenmek üzere."},{"t":"Rezerv erimesi alarmı","b":"Merkez bankası rezervi {v} mlr$. Spekülatif baskı artabilir."},{"t":"Likidite kalkanı inceliyor","b":"Yalnızca {v} mlr$ rezerv kaldı. Acil önlem penceresi daralıyor."}],"inflation":[{"t":"Enflasyon kontrolden çıkıyor","b":"Yıllık enflasyon %{v}. Toplumsal tepki büyüyor."},{"t":"Fiyat istikrarı bozuldu","b":"Enflasyon %{v} ile politika hedefinin çok üzerinde."},{"t":"Hiper-risk bölgesi","b":"%{v} enflasyon hanehalkı satın alma gücünü eritiyor."}],"stability":[{"t":"İstikrar alarm veriyor","b":"İstikrar skoru {v}. Büyük çaplı toplumsal olaylar kapıda olabilir."},{"t":"Toplumsal gerilim tırmanıyor","b":"İstikrar {v}/100. Yönetim manevra alanı daralıyor."},{"t":"Kırılgan denge","b":"İstikrar göstergesi {v}. Küçük bir şok büyük dalgalanma yaratabilir."}],"debt":[{"t":"Borç sürdürülemez seviyede","b":"Kamu borcu GDP'nin %{v}'ine ulaştı. Borçlanma maliyeti hızla artıyor."},{"t":"Mali alan tükeniyor","b":"Borç/GDP %{v}. Piyasalar risk primi istiyor."},{"t":"Borç dinamiği bozuldu","b":"%{v} borç yükü faiz ve büyüme dengesini tehdit ediyor."}],"polCap":[{"t":"Siyasi sermaye tükeniyor","b":"Hükümetin manevra alanı daralıyor. Yeni müdahaleler için toplumsal destek gerekiyor."},{"t":"Politika yorgunluğu","b":"Siyasi sermaye düşük ({v}). Cesur reformlar pahalı hale geldi."},{"t":"Meclis ve sokak baskısı","b":"Sermaye skoru {v}. Her yeni adım siyasi maliyet üretiyor."}]});
  R("events", {"grev":[{"t":"Grev dalgası başladı","b":"Sendikalar ücret ve iş güvencesi talepleriyle üretimi durdurdu. Sanayi üretimi geriliyor."},{"t":"Fabrikalarda iş bırakma","b":"Metal ve lojistik sektöründe grevler yayıldı. İhracat siparişleri aksıyor."},{"t":"Sendika eylemi büyüyor","b":"Genel grev çağrıları yükseliyor; hükümet arabuluculuğa zorlanıyor."}],"protesto":[{"t":"Sokak protestoları","b":"Ekonomik koşullara tepki gösteren gruplar sokaklara döküldü."},{"t":"Meydanlarda gerginlik","b":"Fiyat artışları ve işsizlik protestolara dönüştü."},{"t":"Sivil toplum sokağa indi","b":"Barışçıl yürüyüşler bazı kentlerde çatışmaya dönüştü."}],"buyuk_protesto":[{"t":"Büyük protesto dalgası","b":"On binlerce kişi hükümetin ekonomi politikalarını protesto ediyor. Olaylar büyüyor."},{"t":"Ulusal çapta eylem günü","b":"Başkent ve büyükşehirlerde kitlesel gösteriler. Ulaşım felç."},{"t":"İstifa çağrıları yükseldi","b":"Kalabalıklar hükümeti istifaya davet ediyor; güvenlik güçleri alarma geçti."}],"secim_baskisi":[{"t":"Seçim baskısı artıyor","b":"Düşen onay oranları hükümetin manevra alanını daraltıyor. Muhalefet erken seçim istiyor."},{"t":"Sandık tartışması","b":"Anketler iktidarı geride gösteriyor; koalisyon görüşmeleri speküle ediliyor."},{"t":"Parlamentoda kriz","b":"Güven oylaması söylentileri ekonomi politikasını gölgeliyor."}],"hukumet_degisti":[{"t":"HÜKÜMET DEĞİŞTİ","b":"Toplumsal tepki sandığa yansıdı; yeni bir hükümet kuruldu. Politika belirsizliği arttı."},{"t":"İktidar el değiştirdi","b":"Yeni kabine yemin etti. Piyasalar \"bekle-gör\" modunda."},{"t":"Yönetim devri tamam","b":"Eski ekip gitti; reform vaatleri ve belirsizlik bir arada."}],"otoriter_sikilasma":[{"t":"Otoriter sıkılaştırma","b":"Yönetim, artan istikrarsızlığa olağanüstü yetkilerle yanıt verdi. Sokaklar sessiz ama gerilim sürüyor."},{"t":"Olağanüstü yetkiler","b":"Medya ve sivil alan daraltıldı; \"istikrar\" gerekçesi öne çıkarıldı."},{"t":"Sıkıyönetim sinyalleri","b":"Güvenlik aygıtı genişletildi; sermaye kaçışı endişesi var."}]});
  R("projectDone", ["Uzun vadeli stratejik proje tamamlandı. Kalıcı yapısal etkiler devreye giriyor.","Proje bitti: miras sistemi güncellendi. Rakipler pozisyon almak zorunda.","Tamamlanan altyapı/politika paketi ülkenin küresel ağırlığını değiştirebilir.","Stratejik hedefe ulaşıldı. Piyasalar \"yeni normal\" fiyatlamasına geçiyor."]);
  R("projectProg", ["Proje planlanan şekilde ilerliyor.","Kilometre taşı geçildi; bütçe ve zaman çizelgesi yakından izleniyor.","Saha ekipleri ve bürokrasi uyumlu çalışıyor; gecikme riski düşük.","Uluslararası ortaklar süreci dikkatle takip ediyor."]);
  R("detectionTitles", ["İFŞA: {an}'nin gizli operasyonu ortaya çıktı","SKANDAL: {an} örtülü ekonomik operasyonda yakalandı","Sızıntı: {an} — \"{ins}\" dosyası sızdırıldı","Uluslararası baskı: {an} gri alan operasyonu ifşa"]);
  R("detectionBodies", ["\"{ins}\" operasyonu {by} tarafından belgelendi. Uluslararası tepki büyük.","Kanıtlar {by} eliyle yayımlandı. \"{ins}\" artık inkâr edilemez.","\"{ins}\" dosyası sızdı; {by} brifing verdi. Misilleme sinyalleri geliyor.","Diplomatik kriz: \"{ins}\" operasyonu ifşa oldu. Piyasalar panik alımı yapıyor."]);
  R("disasterFlavor", {"volcano":["Kül bulutu hava koridorlarını kapalı tutuyor; kargo uçuşları deniz yoluna kayıyor.","Tarım kuşaklarında rekolte kaybı derinleşiyor.","Sigorta primleri felaket bölgelerinde üçe katlandı.","Turizm gelirleri çökerken alternatif destinasyonlar doldu."],"suez":["Afrika çevresi rotası liman kapasitelerini zorluyor.","Orta Koridor ve Kuzey Yolu'na ilgi rekor kırıyor.","Konteyner navlunu kriz öncesinin katına çıktı.","Avrupa-Asya tedarik sözleşmeleri yeniden yazılıyor."],"megahurricane":["Sigorta şirketleri hasar taleplerini karşılayamıyor.","ABD'de yeniden inşa maliyetleri bütçeyi zorluyor.","Enerji altyapısı onarımı aylar sürecek.","İç göç dalgası emlak ve işgücü piyasalarını sarsıyor."],"china_quake":["Çip stokları eriyor; otomotiv üreticileri hat durduruyor.","\"Çin+1\" stratejisi yönetim kurullarının ana gündemi.","Batarya ve yarı iletken fiyatları sert yükseldi.","Acil ithalat lisansları ve stok seferberliği başladı."],"tsunami":["Doğu Asya limanları kademeli olarak yeniden açılıyor.","Çip fiyatlarındaki artış elektronik talebini soğutuyor.","Bölgesel üretim kayması Güneydoğu Asya'ya kayıyor.","Sigorta ve lojistik maliyetleri hâlâ kriz seviyelerinde."],"summit_attack":["Liderlik boşluğu küresel kurumları felç etti.","Piyasalar her açıklamada sert dalgalanıyor.","İttifak toplantıları iptal veya erteleme yağmuru.","Güvenlik harcamaları bütçelerde tavan yaptı."],"oil_depletion":["Enerji karneleri gündemde; sanayi elektrik kesintilerine hazırlanıyor.","Nükleer ve yenilenebilir yatırım başvuruları rekor kırdı.","Petrodolar tartışması merkez bankası toplantılarının ana maddesi.","Ulaşım ve gıda enflasyonu enerji şokunu hanehalkına yansıtıyor."],"supernova":["Şebeke onarımları yavaş ilerliyor; bölgesel kesintiler sürüyor.","Analog yedek sistemlere talep patladı.","Dijital ödeme kesintileri nakit kullanımını artırdı.","Uydu ve internet omurgası kademeli toparlanıyor."],"food_crisis":["Tahıl ihracat yasakları domino etkisi yaratıyor.","Gıda kuyrukları birçok başkentte günlük manzara haline geldi.","Gübre ve tohum kıtlığı gelecek sezon rekoltesini tehdit ediyor.","Acil gıda yardımı diplomasisinin sıcaklığı arttı."],"brics_currency":["Merkez bankaları rezerv kompozisyonlarını sessizce değiştiriyor.","Yeni rezerv birimiyle ilk büyük enerji anlaşması imzalandı.","Dolar cinsi borçlu ülkelerde refinansman paniği.","Çok kutuplu finans mimarisi tartışması ana akıma oturdu."]});
  R("help", {"instruments":"<h4>Enstrümanlar — Tam Rehber</h4><p>Her enstrüman bir <b>devlet ekonomi aracıdır</b>. Değiştirmek 1 müdahale slotu + siyasi sermaye harcar. Açık bırakmak (sürdürmek) slot harcamaz. Etkiler üç kanalda akar: <b>pulse</b> (değişim anı), <b>sustain</b> (açık kaldığı her çeyrek), <b>complete/perm</b> (proje bitince kalıcı taban kayması).</p><h5>Tipler</h5><ul><li><b>Toggle (Aç/Kapat):</b> Ya tam açık ya kapalı. Yaptırımlar, projeler, gri alan operasyonları. Hedefliyse açarken ülke seçilir. Kapatınca ilişkinin bir kısmı toparlanabilir.</li><li><b>Slider (0–100):</b> Yoğunluk. 0 = kapalı. Sübvansiyon, stok, sermaye kontrolü, tarife, Ar-Ge… Süreğen etkiler seviye ile orantılıdır (50 → yarı güç).</li><li><b>Sayısal:</b> Faiz %, vergi %, kamu harcaması, döviz müdahalesi (mlr$), QE. Süreğen etki = mevcut değer − ülkenin nötr başlangıç oranı. Örn. faizi nötrün üstüne çıkarmak enflasyonu baskılar.</li></ul><h5>Katman 1 — Yapısal Strateji</h5><p>5–9 yıllık projeler. Slot harcamadan ilerler; bitince <b>miras</b> (kalıcı base shift) bırakır. Örnekler: rezerv para inşası, SWIFT alternatifi, sermaye piyasaları, CBDC, altyapı koridoru, beyin göçü, MEB, uzay/derin deniz, teknoloji standartları, fikri mülkiyet, eğitim ihracı, Brüksel etkisi, Ar-Ge.</p><p><i>Ne zaman:</i> İstikrar ve büyüme görece sakinse. Krizde acil makro araçlara öncelik ver.</p><h5>Katman 2 — Konjonktürel + Makro</h5><ul><li><b>Politika faizi:</b> Enflasyon/kur vs büyüme/işsizlik. Yüksek borçta etki güçlenir; sermaye kontrolüyle kur etkisi büyür.</li><li><b>Vergi / kamu harcaması:</b> Maliye. Vergi borcu düşürür ama büyümeyi ve onayı yer. Harcama büyütür, borç ve enflasyon üretir.</li><li><b>Döviz müdahalesi / gölge FX:</b> Kur savunması rezerv yer. Düşük rezerv veya yüksek enflasyonda zayıflar.</li><li><b>QE:</b> Likidite. Büyüme destek, enflasyon/kur riski. Faiz zaten düşükken büyüme etkisi artar.</li><li><b>Sübvansiyon, stok, sermaye kontrolü, tarife, anti-damping, exim:</b> Ticaret ve sanayi taktikleri.</li><li><b>Yaptırım ailesi:</b> İkincil yaptırım, varlık dondurma, servis yasağı, chokepoint, gıda/enerji silahı. Enerji/gıda silahı yalnızca net ihracatçıda tam güç.</li><li><b>Swap / yardım:</b> İlişkiyi iyileştiren pozitif araçlar; rezerv ve nüfuz maliyeti vardır.</li><li><b>Fiyat kontrolleri:</b> Kısa vadede enflasyon ve öfke baskısı; orta vadede büyüme/istikrar yan etkisi.</li></ul><h5>Katman 3 — Piyasa Operasyonları</h5><p>Casusluk, içeriden ticaret, derecelendirme baskısı, ulusal şampiyon, patent iptali, sertifikasyon, jawboning, dezenformasyon. Birçoğunda <b>tespit riski</b> vardır. Jawboning ucuz ve kısa ömürlüdür.</p><h5>Katman 4 — Gri Alan</h5><p>NGO kullanımı, yolsuzluk ağı, isyan finansmanı, lawfare. En yüksek risk. Tespit: ilişki çöküşü, misilleme vergisi, etki ve onay kaybı. Oyun sonu “risk skoru”na yazılır.</p><h5>4 Slot Kuralı</h5><p>Her tur en fazla 4 farklı enstrüman değişir. Aynı enstrümanı aynı turda iki kez değiştiremezsin (bekleyen kaydı güncelleyebilirsin, yine 1 slot). Onayla ve İlerle → etkiler uygulanır, AI ülkeler tepki verir.</p><h5>Siyasi Sermaye</h5><p>Her müdahale maliyet düşer. Onay yükseldikçe sermaye daha hızlı dolar. Sermaye bitince pahalı araçlar kilitlenir. AI ülkeler de sermaye harcar.</p>","countries":"<h4>Ülkeler — 17 Güç Rehberi</h4><p>Oyun dünyasında <b>17 oyuncuya açık güç</b> vardır. Avrupa Birliği tek varlık olarak oynanır; İngiltere ayrıdır. Her ülkenin göstergeleri, kişiliği, ticaret ağı, küresel bağımlılıkları ve iç grup güçleri farklıdır.</p><h5>Göstergeler</h5><ul><li><b>GDP büyüme:</b> Ekonomik canlılık. Düşük/negatif → teşvik baskısı; yüksek → enflasyon riski.</li><li><b>Enflasyon:</b> Fiyat istikrarı. Yüksekse faiz, stok, fiyat kontrolü devreye girer; istikrar ve onay erir.</li><li><b>İşsizlik:</b> Okun bağı ile büyümeye bağlı. Sübvansiyon/harcama ile düşürülebilir.</li><li><b>Rezerv:</b> Kur savunması yakıtı. Düşükse müdahale zayıflar.</li><li><b>Borç %GDP:</b> Mali alan. Çok yüksekse faiz maliyeti ve crowding-out büyümeyi keser.</li><li><b>Para birimi endeksi:</b> 100 = başlangıç. Düşüş enflasyona geçişkenlik yaratır.</li><li><b>Ticaret dengesi:</b> Rezervi besler; yaptırımlardan etkilenir.</li><li><b>Küresel etki:</b> Standart, yaptırım ve derecelendirme araçlarının gücünü artırır.</li></ul><h5>Kişilik (AI)</h5><p><b>aggression</b> misilleme/yaptırım eğilimi; <b>diplomacy</b> swap/yardım ve yumuşak ton; <b>opportunism</b> kriz fırsatçılığı ve gri alan; <b>patience</b> uzun proje başlatma. Otoriterler gölge FX ve sert misillemeye daha yatkındır. AB <code>birlik</code> tipindedir (demokratik seçim kuralları + yavaş koordinasyon hissi).</p><h5>Bağımlılıklar (deps)</h5><p>Petrol/gıda/çip/navlun/dolar endeksine duyarlılık. <b>Negatif</b> = o fiyat yükselince kazanırsın (ihracatçı). Enerji/gıda silahı bu yüzden yalnızca net ihracatçıda gerçekçi güçtedir.</p><h5>Kısa ülke notları</h5><ul><li><b>ABD:</b> Rezerv para, yaptırım gücü, yüksek borç. Zor.</li><li><b>Çin:</b> Yapısal projeler, tedarik zinciri, yüksek rezerv, sabır.</li><li><b>AB:</b> Brüksel etkisi, ihracat, enerji bağımlılığı, yüksek diplomasi.</li><li><b>Japonya:</b> Teknoloji/finans, dev borç, enerji ithalatçısı.</li><li><b>Hindistan:</b> Hızlı büyüme, petrol bağımlılığı, reform odaklı.</li><li><b>BK:</b> Finans + soft power, AB ile karma ilişki.</li><li><b>Rusya:</b> Enerji silahı, gri alan, yaptırım riski.</li><li><b>Kanada:</b> Emtia + ABD ekseni, istikrarlı kurumlar.</li><li><b>Brezilya:</b> Gıda/emtia kartı.</li><li><b>G. Kore:</b> Çip/ihracat, jeopolitik sıkışma.</li><li><b>Avustralya:</b> Maden/LNG, Çin talebi.</li><li><b>Meksika:</b> Nearshoring, ABD ticareti.</li><li><b>Endonezya:</b> Kritik mineraller, genç nüfus.</li><li><b>Suudi:</b> Petrol süper gücü, egemen servet.</li><li><b>Türkiye:</b> Köprü ülke, enflasyon hassasiyeti, fırsatçılık.</li><li><b>İsviçre:</b> Finans sığınağı, tarafsızlık.</li><li><b>G. Afrika:</b> Maden + BRICS, yüksek işsizlik/istikrar riski.</li></ul><h5>İlişkiler</h5><p>−200…+200. Yaptırım/hedefli hamle düşürür; yardım/swap yükseltir. Tonlu diplomatik mesajlar ilişkiyi hafifçe besler. Her tur yavaş nötre sürüklenme vardır. Üst şeritteki renkler senin ülkeye göre ilişkiyi gösterir.</p>","charts":"<h4>Grafikler — Nasıl Okunur?</h4><p>Merkez paneldeki çizgi grafik, seçtiğin göstergenin <b>zaman serisini</b> çizer. Amaç: “faizi artırdım → enflasyon ne zaman düştü?” gibi neden-sonuç okumaktır.</p><h5>Gösterge seçimi</h5><p>Üstteki çipler: GDP büyüme, enflasyon, işsizlik, rezerv, borç, para birimi, ticaret, küresel etki, onay, istikrar. İyi/kötü yönü renkle ve sol panel oklarıyla da görürsün.</p><h5>Zaman ölçeği</h5><ul><li><b>1 yıl (4 tur):</b> Acil şoklar, faiz ve kur tepkileri.</li><li><b>3–5 yıl:</b> Sübvansiyon, stok, orta vade yapısal adaptasyon.</li><li><b>10 yıl / tümü:</b> Projelerin complete etkileri ve paradigma kaymaları.</li></ul><h5>Motor ile ilişki</h5><p>Her tur simülasyon: mean reversion (tabana çekilme) + pulse tick + sustain + küresel emtia + ticaret yayılımı + Okun/kur-enflasyon bağları + iç dinamikler. Grafik bu bileşik sonucu gösterir; tek bir müdahalenin izini görmek için müdahaleden hemen sonraki 2–8 turu kısa ölçekte izle.</p><h5>Sol panel okları</h5><p>Son turdaki değişim: yeşil = senin için iyi yönde, kırmızı = kötü (göstergenin goodUp meta’sına göre). Küçük dalgalanmalar normaldir; trend ve felaket şoklarına bak.</p><h5>Küresel değişkenler</h5><p>Petrol, gıda, çip, dolar, navlun, küresel ticaret endeksleri (100 = 2026 başı) her ülkeyi deps üzerinden etkiler. Chokepoint/gıda/enerji silahı ve felaketler bu endeksleri iter.</p><h5>İpuçları</h5><ul><li>Enflasyon grafiğini faiz/QE ile yan yana düşün (sırayla bak).</li><li>Rezerv erimesi + kur düşüşü = müdahaleyi bırak / faiz artır sinyali.</li><li>Proje bitince influence/currency/trade’te basamak şeklinde kalıcı sıçrama ararsın.</li><li>Oyun sonunda miras listesi kalıcı kaymaları metin olarak arşivler.</li></ul>","topics":"<h4>Konular &amp; Sistem — Derin Mekanikler</h4><h5>Oyun amacı ve misyon</h5><p><b>Kazanmak yok.</b> Amaç: bir ekonomik enstrümanı değiştirdiğinde dünyada ne olduğunu hissetmek. Güç, sorumluluk ve “keşke şöyle yapsaydım” meraklısı bir simülasyon. 60 tur ≈ 15 yıl; her tur 1 çeyrek (3 ay).</p><h5>Tur akışı</h5><ol><li>Sen en fazla 4 bekleyen müdahale seçersin.</li><li>Onayla ve İlerle → kararların uygulanır, diplomatik tepkiler üretilir.</li><li>AI ülkeler (karışık sıra, gecikmeli haber) kendi adaylarını skorlayıp uygular.</li><li>Simülasyon tick: reversion, pulse, sustain, küresel, ticaret, ekonomik bağlar, projeler, iç dinamikler, tespit.</li><li>Haberler, kayıt, tur artışı. Felaket 2–4. turda bir kez tetiklenir.</li></ol><h5>Etki zaman ölçekleri</h5><p>imm (0 gecikme / 2 tur), short (1/4), med (4/10), long (12/24). Pulse toplam etki bu süreye bölünür. Sustain her çeyrek seviye×m ekler. Mean reversion sınırsız birikimi engeller (büyüme hızlı, borç yavaş döner).</p><h5>Çapraz çarpanlar</h5><p>Yüksek borç × faiz; sermaye kontrolü × faiz-kur; düşük rezerv × FX; felaket × stok; QE × enflasyon; influence &gt;70 × yaptırım/standart; needsExporter × enerji/gıda silahı. Varlık dondurma rezerv şoku hedefin rezervi ve senin gücünle ölçeklenir. İkincil yaptırım ticaret ortaklarına sızar.</p><h5>İç dinamikler</h5><p>6 grup (iş dünyası, emek, milliyetçi, liberal, kırsal, bürokrasi). Enstrüman groups etkileri + ekonomik koşullar memnuniyeti değiştirir. Onay = ağırlıklı ortalama; istikrar kutuplaşma/radikalizm/işsizlik/enflasyona bağlı. Protesto, grev, seçim baskısı, hükümet değişikliği (demokratik/birlik), otoriter sıkılaşma olabilir.</p><h5>Diplomasi ve ton</h5><p>5 ton: dostane → düşmanca. İlişki, eylem şiddeti, gözlemci kişiliği ve self-impact hesaplanır. Sert tonlar ilişkiyi daha da bozar. Haritada tıkla: ülke bilgisi + ticaret hatları.</p><h5>Harita navigasyonu</h5><p>Google Haritalar tarzı: sürükle = kaydır, tekerlek = zoom, çift tık = yaklaş, +/−/⌂ düğmeleri. Ülke sınırına tıkla = o ülkenin paneline geç.</p><h5>AI</h5><p>Skor tabanlı adaylar: öz-bakım, felaket savunması, oyuncu misillemesi, projeler, fırsatçı agresyon. Krizde 3, normalde 2 eylem. Danışma Kurulu aynı motoru senin için çalıştırır.</p><h5>Kayıt</h5><p>localStorage anahtarı <code>kureselEtkiSave_oyungrok</code> (eski /oyun/ sürümünden ayrı). Her tur otomatik kayıt. Eski kayıtlar yeni enstrüman/ülke setiyle uyumsuz olabilir → Yeni Oyun önerilir.</p><h5>Oyun sonu skorları</h5><p>Ülke performansı, küresel istikrar, miras (kalıcı değişim sayısı), proje tutarlılığı, risk (tespit/misilleme). Hepsi 0–100’e sıkıştırılır; “kazanma” değil değerlendirme panosudur.</p>"});
  R("about", "<h4>Misyon</h4><p><b>Küresel Etki</b>, klasik “kazan-kaybet” oyunu değildir. Büyük bir küresel felaket sonrası seçtiğin ülkeyi <b>yalnızca ekonomik enstrümanlarla</b> yönetirsin. Her faiz artışı, yaptırım, stok kararı veya 8 yıllık proje sadece senin GDP’ni değil; ticaret ortaklarını, emtia fiyatlarını, diplomatik tonları ve 15 yıl sonraki küresel düzeni değiştirir. Amaç: <i>“Ben bu aracı değiştirdiğimde dünyada gerçekten ne oluyor?”</i> sorusunu yaşamak.</p><h4>Temel kurallar</h4><ul><li><b>Tur = 3 ay.</b> Oyun 60 tur (≈15 yıl) sürer.</li><li><b>4 slot:</b> Her tur en fazla 4 enstrüman değişikliği. Sürdürmek ücretsizdir.</li><li><b>Siyasi sermaye:</b> Müdahaleler maliyetlidir; toplum onayı sermayeyi yeniler.</li><li><b>17 ülke:</b> AB tek varlık, İngiltere ayrı. AI ülkeler senin hamlelerine tepki verir.</li><li><b>1 felaket:</b> 2–4. turda rastgele tetiklenir; şiddet ülkeye göre değişir.</li><li><b>Gri alan riski:</b> Örtülü operasyonlar tespit edilebilir → skandal + misilleme.</li></ul><h4>Arayüz haritası</h4><ul><li><b>Sol üst ülke şeridi:</b> İlişki renkli kısa adlar; tıkla → dünya haritası (sürükle/zoom).</li><li><b>Sol panel:</b> Göstergeler, iç gruplar, aktif politikalar.</li><li><b>Merkez:</b> Zaman serisi grafikleri.</li><li><b>Sağ:</b> mIRC tarzı olay akışı (#ekonomi, #diplomasi…).</li><li><b>Alt:</b> 4 katmanlı enstrüman menüsü — ekran genişliğine göre <b>sayfalı</b> (kaydırma yok).</li><li><b>❓ Yardım:</b> Danışma Kurulu önerileri + ansiklopedi butonları.</li></ul><h4>Strateji ipuçları</h4><ul><li>Krizde önce makro (faiz, stok, rezerv); sakin dönemde yapısal proje.</li><li>Yaptırım misilleme doğurur; müttefiklere swap/yardım ilişki kazanır.</li><li>Grafikte 1–3 yıl ölçeğini izle — etkiler gecikmeli gelir.</li><li>Her karar bir seçimdir: 4 kötü slot, felaketi büyütür.</li></ul><p style=\"margin-top:12px;color:#505050\"><b>Alttaki butonlardan</b> enstrümanlar, ülkeler, grafikler ve sistem konularında çok daha detaylı metinlere geçebilirsin.</p>");
  R("chartSeries", {"growth":"GDP Büyüme","inflation":"Enflasyon","currency":"Para Birimi","trade":"Ticaret Dengesi","debt":"Kamu Borcu","reserves":"Rezerv","stability":"İstikrar","influence":"Küresel Etki","g:oil":"Petrol (Küresel)","g:food":"Gıda (Küresel)","g:dollar":"Dolar Endeksi"});
  R("ai", {"rate_hike":{"title":"{name} faizi %{from}'den %{to}'e çıkardı","body":"Merkez bankası artan enflasyona sıkılaştırmayla yanıt verdi.","why":"Enflasyon %{infl} — tabanın {gap} puan üzerinde. Faiz artışı enflasyonu ve kur baskısını düşürür."},"qe_slow":{"title":"{name} miktarsal gevşemeyi yavaşlattı","body":"Enflasyon baskısı nedeniyle bilanço genişlemesi frenlendi.","why":"QE enflasyonu besliyor. Likidite musluğunu kısmak fiyat istikrarı için gerekli."},"price_cap":{"title":"{name} temel mallarda fiyat tavanı getirdi","body":"Toplumsal öfkeyi bastırmak için acil fiyat kontrolü.","why":"Enflasyon yüksek ve istikrar kırılgan. Kısa vadede baskılar; orta vadede kıtlık riski."},"rate_cut":{"title":"{name} faiz indirimine gitti","body":"Zayıflayan ekonomiyi desteklemek için para politikası gevşetildi.","why":"Enflasyon kontrol altında ama büyüme zayıf. Faiz indirimi krediyi ucuzlatır."},"qe_start":{"title":"{name} miktarsal gevşeme programı başlattı","body":"Merkez bankası varlık alımlarıyla likidite enjekte ediyor.","why":"Klasik faiz alanının daraldığı ortamda QE büyümeyi destekler."},"stimulus":{"title":"{name} teşvik paketi açıkladı","body":"Kamu harcamaları daralan ekonomiye karşı artırılıyor.","why":"Mali teşvik talebi canlandırır; borç ve enflasyon maliyeti vardır."},"tax_cut":{"title":"{name} vergi indirimine gitti","body":"Özel sektörü canlandırmak için vergi yükü hafifletildi.","why":"Vergi indirimi büyümeyi destekler; mali dengeyi zorlar."},"austerity":{"title":"{name} kemer sıkmaya geçti","body":"Yükselen borç yükü nedeniyle kamu harcamaları kısılıyor.","why":"Borç dinamiğini dizginlemek için harcama kısıntısı."},"tax_hike":{"title":"{name} mali konsolidasyon için vergi artırdı","body":"Borç sürdürülebilirliği için gelirler güçlendiriliyor.","why":"Vergi artışı borcu yavaşlatır ama büyümeyi ve onayı sıkar."},"fx_defend":{"title":"{name} döviz piyasasına müdahale etti","body":"Merkez bankası rezerv satarak kuru savunuyor.","why":"Kur baskısı rezerv maliyetine karşı savunuluyor."},"capital_ctrl":{"title":"{name} sermaye kontrollerini sıkılaştırdı","body":"Sıcak para çıkışına karşı yeni tedbirler devrede.","why":"Sermaye çıkışı kuru ve rezervleri tehdit ediyor."},"shadow_fx":{"title":"{name} gölge döviz operasyonunu devreye aldı","body":"Örtülü müdahale ile kur yönetiliyor.","why":"Açık rezerv satışı yerine örtülü kanal."},"jawbone":{"title":"{name} piyasalara güvence mesajı verdi","body":"Üst düzey açıklamalarla kur ve risk algısı yönetiliyor.","why":"Ucuz iletişim aracı; kısa ömürlü etki."},"fx_stop":{"title":"{name} kur savunmasını durdurdu","body":"Rezervlerin erimesi üzerine döviz müdahalesine son verildi.","why":"Rezervler kritik; müdahale sürdürülemez."},"rate_reserve":{"title":"{name} rezerv kaybını frenlemek için faiz artırdı","body":"Faiz artışı sermaye çıkışını yavaşlatmayı hedefliyor.","why":"Rezerv erimesi ve kur baskısı."},"subsidy_jobs":{"title":"{name} istihdam için sübvansiyonları artırdı","body":"İşsizliğe karşı sanayi ve istihdam destekleri genişletildi.","why":"İşsizlik tabanın üzerinde; istihdam teşviki."},"export_credit":{"title":"{name} ihracat kredi paketini genişletti","body":"Exim tipi desteklerle dış talep çekiliyor.","why":"İhracat ve ticaret dengesi için finansman."},"stocks":{"title":"{name} stratejik stokları güçlendirdi","body":"Toplumsal gerilime karşı gıda ve enerji güvenliği önlemleri.","why":"İstikrar ve fiyat şoklarına tampon."},"national_champ":{"title":"{name} ulusal şampiyon birleşmelerine yeşil ışık yaktı","body":"Yerli devlerin küresel rekabeti hedefleniyor.","why":"Sanayi politikası ve ölçek ekonomisi."},"crisis_industry":{"title":"{name} sanayiye kriz desteği açıkladı","body":"Tedarik şokuna karşı sübvansiyon devrede.","why":"Felaket kaynaklı üretim şoku."},"energy_spend":{"title":"{name} enerji dönüşümü için harcamaları artırdı","body":"Enerji güvenliği yatırımları hızlandı.","why":"Enerji şokuna yapısal yanıt."},"energy_weapon":{"title":"{name} enerji ihracatını silahlaştırdı","body":"Petrol/gaz kısıtı ile jeopolitik baskı.","why":"İhracatçı avantajı kriz döneminde."},"food_weapon":{"title":"{name} gıda ihracatını kısıtladı","body":"Küresel gıda krizinde arz silahı devrede.","why":"Gıda ihracatçısı olarak baskı aracı."},"alt_finance":{"title":"{name} alternatif ödeme altyapısını hızlandırdı","body":"Yaptırım direnci için ödeme ağı güçlendiriliyor.","why":"Finansal yaptırım riski."},"cbdc":{"title":"{name} CBDC sınır ötesi pilotunu genişletti","body":"Dijital para ile dolarsızlaşma adımı.","why":"Rezerv para bağımlılığını azaltma."},"corridor":{"title":"{name} alternatif koridor projesini başlattı","body":"Süveyş tıkanıklığına karşı lojistik diversifikasyon.","why":"Lojistik şokuna yapısal yanıt."},"swap":{"title":"{name}, {target} ile döviz swap hattı açtı","body":"İkili likidite hattı ilişkileri ve ticareti destekliyor.","why":"Diplomasi ve rezerv esnekliği."},"export_fin":{"title":"{name} ihracat finansmanını güçlendirdi","body":"Exim kapasitesi artırıldı.","why":"Ticaret fazlası hedefi."},"tariff_wall":{"title":"{name}, {pname} mallarına gümrük duvarı ördü","body":"Misilleme tarifeleri devrede.","why":"Ticaret misillemesi."},"tariff_ret":{"title":"{name}, {pname} mallarına misilleme vergisi koydu","body":"Karşılıklılık ilkesi devrede.","why":"Yaptırım/tarife misillemesi."},"freeze":{"title":"{name}, {pname} varlıklarını dondurdu","body":"Mali yaptırım sertleştirildi.","why":"Sert misilleme."},"energy_vs":{"title":"{name} enerji musluğunu {pname}'e karşı kıstı","body":"Enerji ihracat kısıtı misilleme olarak kullanıldı.","why":"Enerji silahı."},"stock_shock":{"title":"{name} arz şokuna karşı stok artırdı","body":"Stratejik stoklar yükseltiliyor.","why":"Arz silahına savunma."},"tariff_balance":{"title":"{name}, {pname} mallarına dengeleyici tarife koydu","body":"Sübvansiyon rekabetine tarife yanıtı.","why":"Ticaret dengeleme."},"energy_target":{"title":"{name} enerji silahını {target}'e çevirdi","body":"Hedefli enerji kısıtı.","why":"Fırsatçı baskı."},"chokepoint":{"title":"{name} kritik tedarikte kota uyguladı","body":"Tedarik zinciri silahlaştırıldı.","why":"Stratejik baskı."},"project_start":{"title":"{name} uzun vadeli proje başlattı: {ins}","body":"Stratejik yatırım zaman çizelgesine girdi.","why":"Yapısal güç inşası."},"generic_act":{"title":"{name}: {ins}","body":"Politika ayarı güncellendi.","why":"Skor tabanlı aday."},"aid":{"title":"{name}, {target} için kalkınma yardımı açıkladı","body":"Yardım diplomasisi ilişkileri güçlendiriyor.","why":"Yumuşak güç ve ilişki onarımı."},"detection_scandal":{"title":"Tespit skandalı","body":"Örtülü operasyon ifşa oldu."}});
